import React, { useEffect, useState } from 'react';
import './Header.css';

const Header: React.FC = () => {
  const [showStars, setShowStars] = useState(false);
  const [showAvatar, setShowAvatar] = useState(false);
  const [showText, setShowText] = useState(false);
  const [showCopyright, setShowCopyright] = useState(false);
  const [showLagentry, setShowLagentry] = useState(false);
  const [showNavigation, setShowNavigation] = useState(false);

  useEffect(() => {
    // Animation sequence timing
    const timeline = [
      { delay: 300, action: () => {
        console.log('Stars appearing');
        setShowStars(true);
      }},
      { delay: 1500, action: () => {
        console.log('Text appearing');
        setShowText(true);
      }},
      { delay: 2500, action: () => {
        console.log('Avatar appearing');
        setShowAvatar(true);
      }},
      { delay: 3000, action: () => {
        console.log('Copyright appearing');
        setShowCopyright(true);
      }},
      { delay: 4500, action: () => {
        console.log('Elements disappearing, Lagentry appearing');
        setShowText(false);
        setShowAvatar(false);
        setShowCopyright(false);
        setShowLagentry(true);
      }},
      { delay: 5500, action: () => {
        console.log('Navigation appearing');
        setShowNavigation(true);
      }}
    ];

    timeline.forEach(({ delay, action }) => {
      setTimeout(action, delay);
    });
  }, []);

  // Create enhanced particle effect
  useEffect(() => {
    const createEnhancedStars = () => {
      const particlesContainer = document.getElementById('stars-container');
      if (!particlesContainer) return;

      // Clear existing particles
      particlesContainer.innerHTML = '';

      // Create different types of stars
      const starTypes = ['small-star', 'medium-star', 'large-star', 'twinkling-star', 'shooting-star'];
      
      for (let i = 0; i < 120; i++) {
        const star = document.createElement('div');
        const starType = starTypes[Math.floor(Math.random() * starTypes.length)];
        star.className = `star ${starType}`;
        
        // Position stars within container bounds
        star.style.left = Math.random() * 100 + '%';
        star.style.top = Math.random() * 100 + '%';
        
        // Different animation delays and durations for variety
        star.style.animationDelay = Math.random() * 15 + 's';
        star.style.animationDuration = (Math.random() * 8 + 4) + 's';
        
        // Add variety to star brightness
        const brightness = Math.random() * 0.8 + 0.2; // 0.2 to 1.0 opacity
        star.style.opacity = brightness.toString();
        
        // Add random rotation for some stars
        if (Math.random() > 0.7) {
          star.style.transform = `rotate(${Math.random() * 360}deg)`;
        }
        
        particlesContainer.appendChild(star);
      }

      // Create shooting stars occasionally
      const createShootingStar = () => {
        const shootingStar = document.createElement('div');
        shootingStar.className = 'shooting-star-trail';
        shootingStar.style.left = Math.random() * 100 + '%';
        shootingStar.style.top = Math.random() * 100 + '%';
        shootingStar.style.animationDelay = '0s';
        shootingStar.style.animationDuration = '2s';
        
        particlesContainer.appendChild(shootingStar);
        
        // Remove shooting star after animation
        setTimeout(() => {
          if (shootingStar.parentNode) {
            shootingStar.parentNode.removeChild(shootingStar);
          }
        }, 2000);
      };

      // Create shooting stars periodically
      const shootingStarInterval = setInterval(() => {
        if (Math.random() > 0.6) { // 40% chance every interval
          createShootingStar();
        }
      }, 3000);

      // Clean up interval when component unmounts or stars are hidden
      return () => {
        clearInterval(shootingStarInterval);
      };
    };

    if (showStars) {
      const cleanup = createEnhancedStars();
      return cleanup;
    }
  }, [showStars]);

  return (
    <header className="header">
      <div className="header-background">
        <div className="stars"></div>
        <div className="stars2"></div>
        <div className="stars3"></div>
        
        {/* New Stars Container */}
        <div id="stars-container" className={`stars-container ${showStars ? 'visible' : ''}`}></div>
        
        {/* Avatar */}
        <div className={`avatar-container ${showAvatar ? 'visible' : ''} ${!showAvatar && showLagentry ? 'hidden' : ''}`}>
          <div className="avatar">
            <div className="avatar-face"></div>
            <div className="avatar-body"></div>
          </div>
        </div>
        
        {/* Sliding Text */}
        <div className={`sliding-text ${showText ? 'visible' : ''} ${!showText && showLagentry ? 'hidden' : ''}`}>
          <h2>There's a new Web Dev in town</h2>
        </div>
        
        {/* Copyright */}
        <div className={`copyright-text ${showCopyright ? 'visible' : ''} ${!showCopyright && showLagentry ? 'hidden' : ''}`}>
          <p>© 2024 Lagentry. All rights reserved.</p>
        </div>
        
        {/* Background Lagentry Text */}
        <div className={`background-lagentry-text ${showLagentry ? 'visible' : ''}`}>
          <h2>Lagentry</h2>
        </div>
      </div>
    </header>
  );
};

export default Header;
